# --- Part 1: Prime Number Finder using for/else ---
print("Primes from 2 to 20:")
for candidate in range(2, 21):
    for divisor in range(2, candidate):
        if candidate % divisor == 0:
            break              # not prime — exit the inner loop
    else:
        print(candidate, end=" ")   # only prints when no break occurred
print()

# --- Part 2: Skip negatives with continue ---
readings = [12, -5, 34, -2, 0, 89, -11, 45]
valid_total = 0
print("\nValid (non-negative) readings:")
for r in readings:
    if r < 0:
        continue          # skip negative values
    valid_total += r
    print(r, end=" ")
print(f"\nTotal of valid readings: {valid_total}")

# --- Part 3: Search with break and else ---
inventory = ["pen", "notebook", "ruler", "eraser"]
search    = "stapler"
print(f"\nSearching for '{search}':")
for item in inventory:
    if item == search:
        print(f"Found '{search}'.")
        break
else:
    print(f"'{search}' is not in inventory.")

