prices = [50, 200, 450, 80, 300, 999, 30]
target = 450
count  = 0

print("Valid prices (>= 100):")
for price in prices:
    if price < 100:
        continue
    print(price, end=" ")
    count += 1
print(f"\nValid count: {count}")

for price in prices:
    if price == target:
        print(f"Found {target}")
        break
else:
    print("Price not found")
